import json
b = json.load(open('baseline-packages.json'))
a = json.load(open('after-cpm-packages.json'))
# Compare package versions per project (ignoring paths)
for bp, ap in zip(b['projects'], a['projects']):
    for bf, af in zip(bp['frameworks'], ap['frameworks']):
        for bpkg, apkg in zip(bf['topLevelPackages'], af['topLevelPackages']):
            if bpkg != apkg:
                print(f'DIFF: {bpkg} vs {apkg}')
print('All packages match - conversion is version-neutral')
